code.JavaScript:
const readline = require('readline').createInterface({
    input: process.stdin,
    output: process.stdout
});
let i = 0;
let n;
let arr;
readline.on('line', line => {
    if (i === 0) {
        n = parseInt(line);
    } else {
        arr = line.split(' ').map(num => parseInt(num));
        let maxIncrease = 0;
        for (let j = 0; j < n; j++) {
            for (let k = j + 1; k < n; k++) {
                if (arr[k] > arr[j]) {
                    maxIncrease += arr[k] - arr[j];
                }
            }
        }
        console.log(maxIncrease);
        readline.close();
    }
    i++;
});
